INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('680278cde3c98b0941765738', '花园酒店是这次广州行的最大惊喜，真的是惊喜多多。首先硬件无可挑剔，交通方便，门外就是地铁站。无论大堂还是房间得设施真的是感觉非常棒，免费升级房间、赠送早餐、享用行政酒廊、收到生日蛋糕……，真的贴心。服务真的一级棒，可以说每个服务员都是经过专业的培训，要夸赞花园酒店的管理层真的不错呢！要夸赞行政酒廊的Carrie和Blair，真的是笑容服务，会和客人温柔的聊天，很有亲和力。园子里的锦鲤也是超好看，下次去广州还会住这里！', '["https://dimg04.c-ctrip.com/images/0231512000im0h1pb01C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000im0pxuz0BCC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000im0pw39B411_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235j12000im0pxv1D6D1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000im0syz7080B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234l12000im0nkaaD7B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000im0l7x58687_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000im0ebjbAA9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000im0l7x71EF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-19', '花园大床房', '大床房', '家庭亲子', 210, 0, 2, 9, '["整体满意度","前台服务","交通便利性"]'::jsonb, '整体满意度', '前台服务', '交通便利性'),
('680278cde3c98b0941765739', '环境：不愧是花园酒店，后花园和瀑布太美了。
服务：态度很好，大部分人都主动打招呼、提供帮助。入住时小姐姐还帮我们升了套房，非常感谢。
卫生：很不错，很放心。
设施：全皮办公桌椅很气派，但可能是太久了，卫生间的马桶圈小了一圈，还晃来晃去不合适，和整体风格格格不入。一个洗手池下水极其缓慢，另外一个洗手池下水也很慢。', '["https://dimg04.c-ctrip.com/images/0233g12000ijwww2c9660_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ijwtiji38AE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000ijwzxp856F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230d12000ijxejz7E447_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000ijxkrlmC2B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231912000ijxejz9E686_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-16', '花园双床房', '双床房', '家庭亲子', 156, 1, 9, 8, '["房间设施","前台服务","卫生状况"]'::jsonb, '房间设施', '前台服务', '卫生状况'),
('680278cde3c98b094176573a', '酒店房间干净、卫生。酒店本身自带的花园非常漂亮，瀑布餐厅早餐品种丰富。打扫房间的东南亚小哥认真负责。酒店边上就是淘金地铁站，外出方便。周边吃饭餐馆选择多，以后来广州还会选择花园酒店。

另外酒店有直达香港，澳门的巴士，去港澳非常方便。', '["https://dimg04.c-ctrip.com/images/0231b12000in4zau2DD93_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000in52vvv6087_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-20', '花园双床房', '双床房', '家庭亲子', 117, 0, 10, 8, '["卫生状况","交通便利性","周边配套"]'::jsonb, '卫生状况', '交通便利性', '周边配套'),
('680278cde3c98b094176573b', '花园酒店是中国星级酒店的代表，三家白金五星级酒店之一，大堂气派，尽管酒店很有历史，设施并不陈旧。红棉大床房对于家庭出行很方便，客厅有专门的写字桌和台灯，孩子晚上方便写会作业。早餐选择的30层旋转餐厅，虽说味道一般，但是感觉还不错。周边交通方便，吃喝逛都很方便。总体来说，性价比很高，值得推荐。', '["https://dimg04.c-ctrip.com/images/0234b12000ifsp5450E8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000iftpxwrC9F3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235412000ifto5gc1B58_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231312000ift50gnB97E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000iftn76fDA17_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-10', '红棉大床套房', '套房', '家庭亲子', 146, 0, 6, 9, '["性价比","周边配套","房间设施"]'::jsonb, '性价比', '周边配套', '房间设施'),
('680278cde3c98b094176573c', '带着老人小孩出行，前台办理入住没有排队，帮我两个房间都升级了套房。30楼旋转餐厅的早餐还不错，各种样式的菜都有。旁边就是淘金地铁站，出门打车也很方便。酒店出去右手边有个点都德不远。对面有个购物中心，很方便', '["https://dimg04.c-ctrip.com/images/0234312000in5ukniABE9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000in5jgqf339A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000in5kscoBE05_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000in5fkvr0423_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000in5jgqhB7ED_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-20', '花园双床房', '双床房', '家庭亲子', 102, 0, 23, 8, '["前台服务","交通便利性","周边配套"]'::jsonb, '前台服务', '交通便利性', '周边配套'),
('680278cde3c98b094176573d', '酒店很高大上，考虑了康莱德和白天鹅，最后还是选这里，也因为白金五星的历史感。花园和博物馆都不错，博物馆很有情怀，不虚此行。
早餐很好，选的30层旋转餐厅，大部分菜品味道在线。晚餐是荔湾亭点心半自助，以一个外省人的角度很好吃。
健身的地方有点不好找，但设施还行，该有的都有，不大。
停车不方便，地下停车场离大厅有距离，地上停车场又比较小，自驾游可能要考虑下停车的预案。门口就是地铁站，地铁很方便。
花园双床房非常小，小到唤起我对某些日本酒店的印象：地上能不能平铺开行李箱？能平铺开就算是大房间。按这个标准，这里的也算大房间。但如果再住这里的话，我不会选基础房，俩大人带个孩子太局促了。
有点逗的是晚上22-23点房间出现高频断续刺耳异响，我推断是某些房间用水或者是上下水导致的水管尖锐鸣声。当时孩子已经睡了，俩大人面面相觑，客房服务人员A来的时候没响，她说自己很忙，也没法停留五分钟听一下到底是什么声音，解决方案是要么我们自己内线拨0沟通换房，要么她送耳塞过来。我们的诉求是请她优先解决声音问题，解决不了再换房，毕竟孩子睡着了，不太想折腾。过了一会来了个客房服务B，只送来一副耳塞并且当场听到了连续且刺耳的声音，说立刻回去报告，然后就没有然后了。俩成年人一副耳塞，问题也假装不存在，大半夜大家可能都比较累，凑合睡吧。', '["https://dimg04.c-ctrip.com/images/0232m12000iee56tfBA99_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k12000iedr9xd8241_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000ieddjzaF0B6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2025-02-08', '花园双床房', '双床房', '家庭亲子', 557, 3, 11, 9, '["房间设施","客房服务","交通便利性"]'::jsonb, '房间设施', '客房服务', '交通便利性'),
('680278cde3c98b094176573e', '房间很好，早餐也不错，品种齐全，楼顶旋转餐厅视野无敌。花园太美了，散步根本不想上楼。无论晴天阴天，白天还是夜晚，都好适合散步。
游泳池是露天的，但不恒温。
器械也可以。24小时
下次还来', '["https://dimg04.c-ctrip.com/images/0236312000ioze5h0DE96_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000iozcgit8274_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000ioyirngFD47_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000ioyswww0874_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236812000ioypyu2766D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000ioypyu4D8A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235k12000ioz5tk6D023_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236p12000ioz9wgkA6E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000ioz0p5l080C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-23', '花园大床房', '大床房', '独自旅行', 93, 0, 9, 7, '["餐饮设施","公共设施","整体满意度"]'::jsonb, '餐饮设施', '公共设施', '整体满意度'),
('680278cde3c98b094176573f', '首先说说地理位置，酒店位于广州的越秀区，周边有商场及饭店吃喝都很便利，酒店门口就有一个地铁站无论是坐公共交通还是打车都很方便。 再说说环境，酒店非常大还自带一个后花园饭后散散步十分惬意，除此之外酒店的四楼还有一个关于酒店历史的博物馆住店客人是免费的值得一逛，房间和公共区域都非常干净。 所有的服务人员都非常礼貌、看到客人都会主动打招呼，即便春节期间入住客人非常的多但服务人员的精神面貌都非常好！ 最后来说说房间，卫生情况是不需要担忧的非常干净，但毕竟是1985年就开业的酒店，房间的布局及设施稍稍落后了一些，没有USB插头、吹风机还是最老式的那种，洗浴后没有能放干净换洗衣物的地方，且浴室及床之间仅有一扇透明的隔门（建议稍稍改进一下）。但总体来说酒店很棒，如有机会再次来广州一定还会选择花园酒店', '["https://dimg04.c-ctrip.com/images/0235d12000iizo4qnE6BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000iizjych9F24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234712000iiyyetwFE52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234k12000iizc8urBF3E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n12000iiz2eqb09CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000iizkg6y92B6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232s12000iizjusfC75F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f12000iizk2xwB718_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-14', '花园大床房', '大床房', '家庭亲子', 347, 0, 7, 9, '["房间设施","交通便利性","周边配套"]'::jsonb, '房间设施', '交通便利性', '周边配套'),
('680278cde3c98b0941765740', '服务：前台接待的小姐姐服务超级赞，帮我们从红棉升到了海韵，送了两支鲜花，给我们介绍了酒店、酒店套餐、博物馆和周边交通，很暖心。
住：房间整体不错，床品很舒服，房间除了没有浴缸外，其他都不错。
吃：早餐和其他五星相比品种不多，胜在瀑布餐厅环境不错；酒吧外国人比较多，有驻唱歌手，唱得很棒，但鸡尾酒很一般。荔湾亭菜品不错，说古很有传统特色，但服务员之间频繁相互呛声，稍显不够友爱。', '["https://dimg04.c-ctrip.com/images/0232612000ifpamjsDA6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000ifo3s7oD26E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000ifo5q3cC7FE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233l12000ifnys4sA368_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000ifok2kz2F06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000ifoywkc7D95_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000ifod14s117A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.1, 4, '2025-02-10', '红棉双床套房', '套房', '家庭亲子', 188, 0, 6, 9, '["前台服务","房间设施","餐饮设施"]'::jsonb, '前台服务', '房间设施', '餐饮设施'),
('680278cde3c98b0941765741', '8年前曾经住过的酒店留给我很好的印象，所以这次来广州旅游一定要再体验一下。酒店位置很方便，地铁淘金站出来就到了，马路对面就是广州酒家和友谊商店，附近还有点都德。这次订的花园大床房，房间虽不大，但布局合理，送了欢迎水果：苹果香蕉沙糖桔很甜，房间里有胶囊咖啡机，和川宁茶包，提供的水是屈臣氏绿瓶矿泉水。早上10点到的酒店，被告知要下午2点才能入住，所以到门口寄存处把行李寄好就到对面广州酒家喝早茶去了。在此要表扬寄存处的工作人员（外籍）很有礼貌，很有绅士风度。还有进出酒店都有门童帮忙拉门并热情打招呼，这都是酒店留给我的好印象，并且一直保持到现在，真的是很不容易！不愧是老牌超五星酒店的优良传统，希望一直保持下去。（忘记拍照了，放几张广州夜景照）', '["https://dimg04.c-ctrip.com/images/0235f12000ip244gbBABC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231d12000ip14ifp8798_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000ip19xfq62C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236012000ip1jiju6D69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-23', '花园大床房', '大床房', '家庭亲子', 321, 0, 19, 9, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('680278d8e3c98b0941765742', '老牌五星级酒店，高质量体验和床品用品，窗外风景充满老广州风情，周边美食丰富，环境优雅，出门地铁站，商务出差不二选择', '["https://dimg04.c-ctrip.com/images/0233512000jtfxsyt2BB3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233712000jtfsijxF1FB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000jtfu8xaA38C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-15', '花园大床房', '大床房', '商务出差', 57, 0, 6, 8, '["整体满意度","周边配套","交通便利性"]'::jsonb, '整体满意度', '周边配套', '交通便利性'),
('680278d8e3c98b0941765743', '前台小哥Kasas很棒，升级套房，两个早餐，表扬一下。
环境地段不错，可是下面在修路，早上八点就开始吵到中午12点，基本不用休息了。
设施太老旧，勉强合格，不能抱太大期望，毕竟老牌五星。
早餐种类多，还行。
总经理不行，啥房费没得赔偿了。', '["https://dimg04.c-ctrip.com/images/0231812000j3f5n3aD839_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235v12000j3f6hg34BCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235q12000j3foyj84F1B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.1, 3, '2025-03-15', '花园大床房', '大床房', '情侣出游', 119, 0, 24, 7, '["前台服务","安静程度","餐饮设施"]'::jsonb, '前台服务', '安静程度', '餐饮设施'),
('680278d8e3c98b0941765744', '超预期的好评，也感叹40年用心经营的本土酒店品牌也可以很棒。因为过年带父母和孩子一起到广州旅行，去之前几乎在携程上把所有千元左右的广州五星酒店做了研究，重点看了差评，起初还有些担心，因为有评论说酒店设施老旧、服务不够周到等等，所以我订了2晚花园，同时订了1晚价格比花园略高的国际连锁君悦，负责任地说，花园完胜，第一次在携程上给住过的酒店写评价，所谓国货之光，花园值得拥有。一是40年的历史文化积淀，让花园在广州五星酒店里成为综合性价比翘楚。地处老城区越秀，其实去哪里都很方便，特别适合带孩子老人来。酒店占地广，气派，还拥有独立的花园，4楼开辟出了酒店博物馆，彰显白金酒店的荣誉和情怀。老人和孩子一定特别喜欢。二是有人情味的服务。服务员非常多，引导车辆的、殷勤开门的门童、热情存取行李的礼宾、随时关注你拍照、问询需求的大堂引导都不必说，而且，那么大的酒店、那么多楼层，竟然每层都有个人随时提供服务，餐厅和酒店各处中英切换的外籍服务员也很多，连后花园的池子里都没有飘落的落叶，因为有三个身着花园工装服的工作人员一直在打扫……看得出来，每个工作人员都认真负责，我女儿说：“花园酒店里的锦鲤都很热情，一点不怕人，脚步声到哪里，锦鲤就跟到哪里。”是的，我女儿还第一次摸了锦鲤头。三是贴心的服务，努力让顾客获得最佳体验的初心不是随便说说，是做到了！因为订了两个大床房，所以我希望能挨在一起，同时希望安排安静的房间。真的，都满足了的。而且，入住时因为跟引导沟通有误，现场的客人太多了，导致2点办理入住时并没有马上排到房间。我抱怨了一句，听说我下午3点30约了景点导游，前台马上送了我一个下午茶，我就带着父母孩子去水吧喝咖啡、吃水果、吃蛋糕，点心和服务都很棒，当天晚上入住的时候还送来了一份欢迎水果，酒店的用心和细心可见一斑。因为酒店入住客人多，每个楼层都放了早餐就餐指引，还有工作人员现场解说，告诉我们可以到不同的三个餐厅用餐避免拥堵。四是当然也有不足，但瑕不掩瑜，如果5分满分，我仍然愿意给到4.9分。40年的房子，我住的大床房并不大（跟后面住的君悦比，但君悦真的只能是房间大点，其他软硬件差远了），房间尽力维护了，隔音是很好的，但里面有些设计是鸡肋，比如大床房的浴缸，放在梳妆台前，挡道且容易溅水到床上，拥挤；厕所和淋雨室共用一道移动门，很尴尬；有些角落还是没有打扫干净，比如放胶囊咖啡的盘子。荔湾亭价格和品质不符合，服务虽好，但没有主动告知住店客人可以打折。促使我写这条长长评论的原因是，网上刷流量的一些评价，让我行前顾虑重重，保底订了一晚君悦（携程评分比花园高），两家都住了以后，我还是觉得，作为一个中国人，应该有基本的“中国人不骗中国人”的自觉，以及国货自信，花园几乎有三分之一的客人是外国人，而6号我在君悦早餐时，差不多上座5分之四的餐厅，一眼看去外国人只有2个，所以，国际友人比我们会用脚投票，而我们太容易被刷来的流量绑架，如果下次再来广州，我一定再选花园酒店，白金品质，用心经营。（欢迎大家去看我对君悦的对比评价，真的，我必须对刷流量说不，因为广州君悦，我不会选任何一家君悦，因为徒有其名，所谓国际连锁，更像个旅馆）。', '["https://dimg04.c-ctrip.com/images/0235e12000icu9xxx0A53_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236212000icteum08C76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j12000ict0qoi68DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '花园大床房', '大床房', '家庭亲子', 1310, 2, 4, 10, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('680278d8e3c98b0941765745', '酒店环境优美，特别是后花园的小桥流水，假山瀑布，花草非常漂亮。服务一流，服务员主动帮忙按电梯、拿行李和带路，还免费升级房间。设施非常齐全，卫生干净整洁！是商务旅游的首选！', '["https://dimg04.c-ctrip.com/images/0233n12000j1ddlweC4CD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000j1ddozmC796_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000j1d6fi1420B_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-12', '花园大床房', '大床房', '情侣出游', 85, 0, 32, 9, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('680278d8e3c98b0941765746', '花园酒店环境整体设计很有特色，交通非常便利，淘金地铁站出门就是，打车也非常方便。房间干净、整洁，所有服务人员都很礼貌热情，特别感谢行政酒廊的服务员，帮我打印了好多文件，非常感谢！', '["https://dimg04.c-ctrip.com/images/0230p12000j6if2uwE866_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000j6hhef59589_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000j6h63579BFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000j6hnz9qC45F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000j6inp683D9A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000j6hyau3839D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000j6ig48cF1F7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000j6h4ei0F00A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236112000j6ihgct2CB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-19', '粤韵大床套房', '套房', '其他', 89, 0, 51, 9, '["交通便利性","卫生状况","前台服务"]'::jsonb, '交通便利性', '卫生状况', '前台服务'),
('680278d8e3c98b0941765747', '一座有历史的酒店??，有酒店博物馆，有美丽的后花园。早餐丰富好吃??，服务人员很多，营造出宾至如归的氛围，很满意。美中不足的也是历史的缺憾，客房很干净，打扫及时，就是硬件设施有点陈旧，有点问题的设施跟前台服务反应后工程部也能及时修理处理，并有联系卡，值得表扬。', '["https://dimg04.c-ctrip.com/images/0234t12000ie1nsk67C84_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232812000ie1r0qr3073_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000ie0w27fF581_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236612000ie25ynuEFBA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237112000ie0znmo8F07_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-08', '花园双床房', '双床房', '家庭亲子', 130, 0, 7, 8, '["整体满意度","房间设施","前台服务"]'::jsonb, '整体满意度', '房间设施', '前台服务'),
('680278d8e3c98b0941765748', '春节期间 价格翻倍 普通大床什么的已经没了，定了个城央绿意房型，外面就是这样的景致，还比普通房型贵。虽然是岭客会员金卡，但是由于房满，所以也没有升级房型，送了行政酒廊和早餐，但是早餐人太多要排队，第一天我们出去吃了，第二天起个早不排队了但是也是真的不好吃。房间类似于比较老的快捷酒店，完全没有五星酒店的舒适度，浴缸袋子也没有，我们自己叫了外卖，对了外卖要去楼下外卖柜拿。说实话800一晚非常不值更别提春节1400+每晚的价格，旁边就是全季，和老公说，还不如住全季了', '["https://dimg04.c-ctrip.com/images/0234l12000ifw6l4tDCB9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233912000ifwrswc8353_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000ifwnw77AD28_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2025-02-10', '城央绿意大床房', '大床房', '家庭亲子', 232, 1, 4, 8, '["性价比","房间设施","餐饮设施"]'::jsonb, '性价比', '房间设施', '餐饮设施'),
('680278d8e3c98b0941765749', '预定之前其实是很纠结的，怕酒店年代久远房间设施跟不上。结果到了以后，发现各方面简直超出预期。酒店的外观和大堂超级豪华，就算春节期间服务员的服务也是比较跟得上的，就是办理入住稍微慢了一点。订的红棉大床房，房间很大，住着很舒服。酒店地理位置不错，附近找各种吃的都很方便。', '["https://dimg04.c-ctrip.com/images/0232c12000iaslx4mF6EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000ias1u1dC8E4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-04', '红棉大床套房', '套房', '家庭亲子', 133, 0, 4, 8, '["房间设施","周边配套","整体满意度"]'::jsonb, '房间设施', '周边配套', '整体满意度'),
('680278d8e3c98b094176574a', '不愧为三家白金五星之一，景色漂亮，服务热情，房间宽敞，没有看出网上说的老旧，只体验到了年代感带来的厚重，比较遗憾的是因为广州实在太好吃了和春节泰安门停业的原因，没有选择在酒店用餐，错过了瀑布餐厅和旋转餐厅，
作为酒店同行参观了住宿业博物馆，对酒店业的发展颇为自豪，祝中国的酒店行业越来越好，服务管理越来越专业', '["https://dimg04.c-ctrip.com/images/0236c12000icbhjyp0F17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000icaqqufB829_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234012000icby8snBD4D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-06', '红棉大床套房', '套房', '情侣出游', 154, 0, 3, 9, '["整体满意度","景观/朝向","前台服务"]'::jsonb, '整体满意度', '景观/朝向', '前台服务'),
('680278d8e3c98b094176574b', '总体还是很满意的，酒店后花园很美，大堂气派有老牌五星的风格，酒店门口一直有出租车等候外出很方便。房间洗澡水大，床品很舒服睡眠很好，提供质量很好的肥皂我很喜欢，现在很多酒店都是洗手液。饮用水也很不错，服务也很好有求必应也都会主动打招呼。小缺点就是房间较小，所以做成了开放式卫生间，马桶间和淋浴间空间就比较小，墙纸因为年久也有些旧，不过装修风格我还是喜欢的。早餐比较一般，品种不算少，但未见广州特色，好歹弄个叉烧包啥的呢。早餐可以在1、3、30楼吃，推荐30楼旋转餐厅吃，视野好每桌有间隔。', '["https://dimg04.c-ctrip.com/images/0236c12000ibkamgn42AC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000ibkiaxxFDA6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000ibjusp70FDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r12000ibkhbjf5716_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235b12000ibk7uekE607_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000ibkriqd02A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234x12000ibktw27CAFC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000ibkh88z5CF3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235912000ibk6er2FC86_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 243, 0, 20, 9, '["房间设施","整体满意度","交通便利性"]'::jsonb, '房间设施', '整体满意度', '交通便利性'),
('680278e3e3c98b094176574c', '老酒店的缺点就是卫生死角太多打扫不仔细，房间灯上全是灰茸太恶心了??洁癖慎住！加上房间不像新酒店那么宽敞。入住时没有介绍早餐，其实有三个地方可以吃早餐，但是问工作人员几位口径居然都不一致，完全不太了解一样！这点很差！瀑布餐厅是无猪肉餐厅，早餐很简单寡淡。但是酒店的其他方面还是不错的，过年期间很有年味，服务人员也都比较有礼貌。楼上还有博物馆但是非得扫码注册才能进，很麻烦，建议住店人员直接刷房卡进。2楼荔波亭餐厅实测比3楼桃园口味更好！桃园餐厅不建议！', '["https://dimg04.c-ctrip.com/images/0235x12000iehwxnl1806_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.2, 3, '2025-02-08', '花园大床房', '大床房', '家庭亲子', 226, 0, 9, 8, '["卫生状况","餐饮设施","前台服务"]'::jsonb, '卫生状况', '餐饮设施', '前台服务'),
('680278e3e3c98b094176574d', '春节带娃和老人去广州游玩，入住花园酒店，地铁5号线淘金站A出口，非常方便。双床房的房间不大，设施略显陈旧，但是酒店的环境不错，带娃看了花园瀑布，池子里的鱼都很大了，预约参观了酒店的博物馆，了解了酒店业的发展历史，瀑布餐厅和30楼的早餐到11点，人多需要排队拿号，最推崇的是酒店服务人员的贴心服务，看到我们饮用水都喝完了，特意写了卡片，帮我们多放了两瓶水，真的感受到了贴心和用心！', '["https://dimg04.c-ctrip.com/images/0235j12000i9ya685D445_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230a12000i9y9rqo6E03_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235012000i9y9yc92CAA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235412000i9y6nk72946_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230y12000i9y6ah69BFA_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230l12000i9y6u8c3C5D_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233p12000i9y734zCEE7_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230712000i9yanfhB72B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236412000i9yaweo7BEA_R_150_150_R5_Q70_D.png"]'::jsonb, 4.8, 4, '2025-02-03', '花园双床房', '双床房', '家庭亲子', 189, 1, 1, 9, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('680278e3e3c98b094176574e', '作为一家老五星酒店，腔调还是有的，房间设施维护的也不错，地理位置也很方便，但有几点感受可以给大家做个参考：
1、服务十分机械化，流程很长，就是那种星级酒店的繁琐且不会变通，实用性不多，比较鸡肋；
2、朝向马路那一面的房间，晚上还是很吵的，车流鸣笛声比较影响睡眠，睡眠质量不好的千万别选；
3、早餐真心很一般，418一位/日的价格，性价比无极低，真的没有外面随便一个老铺子做的好（点了早餐外卖比较过），订房千万别选含早餐的；而且如果预约了景点，来不及进去吃要打包的话，还要按他们的标准，标准就是几个非常不好吃的牛角包面包而已，几百块买这些东西，真是奇迹；
4、因为睡眠浅和酒店沟通过三次不要朝向马路的房间，结果还是给了朝向马路的。前台说是朝外花园的，但你们外花园旁边不就是大马路吗？而且订单中备注的小朋友床围也完全没有准备，甚至都没提及，不知道是真的没看见还是当做没看见；
5、不知道是不是春节期间房间紧张，给了朝马路的房间便罢了，而且还是个尾房；以前总听同事提起不要住尾房，但我想着春节期间尽量不找麻烦，所以就没说什么。但是重点来了，真的睡不好，各种奇怪的梦各种醒，每天起床都疲惫不堪。我原以为是自己睡眠不好，结果我那睡觉如小猪的8岁女儿，每夜也是翻来覆去至少醒三次，以至于黑眼圈和浮肿都出来了。以前带她旅游从未如此，建议大家还是谨慎的点吧。
总之，体验感不好，可能之前对花园酒店期望太高了。', '["https://dimg04.c-ctrip.com/images/0230312000i9bj1qv0C8F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.7, 2, '2025-02-02', '红棉大床套房', '套房', '家庭亲子', 596, 2, 5, 9, '["安静程度","性价比","前台服务"]'::jsonb, '安静程度', '性价比', '前台服务'),
('680278e3e3c98b094176574f', '超级失望的入住，没有任何服务，春节在大厅搞活动，又吵又乱，根本没有人服务，办个入住，也一问三不知。考虑到床小，我们要改成大床房，办理入住的服务生告知，只能住双床，加床要三百多。导致我第一晚根本没有睡觉，在沙发上窝了一晚。第二天找到前台经理换了大床房，加了床。最让人无语的是，找到经理投诉，完全是敷衍。总之，没有服务意识的酒店，以后不会再入住了。这个酒店，最大的问题是，没有服务意识，根本没有那种为客人服务解决问题的概念。唯一可取的是景色吧。', '["https://dimg04.c-ctrip.com/images/0233n12000ipn27u67ACA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232f12000ipnhy4y49D7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235n12000ipnwjo5A99F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2025-02-24', '粤韵双床套房', '套房', '家庭亲子', 220, 0, 10, 9, '["前台服务","安静程度","整体满意度"]'::jsonb, '前台服务', '安静程度', '整体满意度'),
('680278e3e3c98b0941765750', '这次出游安排了3日2夜，预订的红棉房还没有清洁完毕，就安排了粤韵房。
前台服务：一般吧，没有说明清楚入住期间所包含的餐饮或其他新春活动
房间：没有床围可以提供，然后电热水壶问题，经过2次沟通，换了全新的+10支蒸馏水备用，这个很好，为表歉意还送了1份水果+3只羊公仔（因为有3个孩子），服务员唐苓，很好，2个黑衫的经理也很好，知道我退房那天还有亲戚过来一起吃饭，还帮我延迟退房到3点
行政酒廊：下午茶不论服务还是食物出品，都很不友好，晚上的欢乐时光，出品还不错，服务员Carrie很好，特别表扬一下。', '["https://dimg04.c-ctrip.com/images/0233b12000iaw6n03758B_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235g12000iaw6rsz5E19_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233c12000iaw72i8FAD4_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0233y12000iaw6o2nC6DF_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231e12000iaw6t6q8A22_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234q12000iaw7ngj90FE_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230j12000iaw6t75C26F_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0237112000iaw7ip20346_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231h12000iaw766u99D4_R_150_150_R5_Q70_D.png"]'::jsonb, 4.5, 4, '2025-02-04', '红棉双床套房', '套房', '家庭亲子', 250, 0, 8, 8, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('680278e3e3c98b0941765751', '1.怀旧打卡还是值得的，check in 大年初一也很快。酒店春节有很多活动，年味足
2.房间干净，设置太老！虽然翻新但是墙壁还是很多水泡后的脱皮，最恼火的是卫生间很小还做了隔断，胖点的住客还是有点局促了', '["https://dimg04.c-ctrip.com/images/0236x12000iatz8f84305_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p12000iatqrpuD839_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000iatss7k7BDE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000iatwmng3AE3_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2025-02-04', '花园大床房', '大床房', '其他', 102, 0, 6, 7, '["退房/入住效率","整体满意度","房间设施"]'::jsonb, '退房/入住效率', '整体满意度', '房间设施'),
('680278e3e3c98b0941765752', '非常感谢1月29日晚上及1月30日白天在9层服务的服务人员！由于空调有问题，房间比走廊还冷，反映了之后，29日晚间的服务人员迅速拿来了暖炉解决了当下的温度问题。30日白天的服务人员早饭后又进行了跟进，在我自己都怕叫空调师傅麻烦的情况下，帮我们督促了检修，晚上回来后发现房间温度舒适。感谢各位服务人员对应迅速，工作有交接，行动力满满，让来广州过年的我们有一个美好的开始～谢谢！', '["https://dimg04.c-ctrip.com/images/0230412000i7dc1i2248C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-01-31', '城央绿意大床房', '大床房', '情侣出游', 187, 1, 10, 9, '["客房服务","房间设施","整体满意度"]'::jsonb, '客房服务', '房间设施', '整体满意度'),
('680278e3e3c98b0941765753', '老牌五星级酒店，如名字一样，花园式环境，交通便利，出门就是地铁口，附近很多美食，个人出行，商务出行都是很好的选择', '["https://dimg04.c-ctrip.com/images/0230m12000jljv1pe9A62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c12000jljihgh5DCA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232m12000jlj8v5jAE3A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-06', '红棉大床套房', '套房', '家庭亲子', 56, 0, 9, 7, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('680278e3e3c98b0941765754', '对花园酒店情有独钟，印象最深的就是服务好！已多次入住了，今年大年初一和家人入住，体验很好??
年初二中午在桃园馆用餐，其间我儿子突然肠胃不适，当时也没告诉我们，他因肠胃绞痛浑身发冷，自己就躺在了在桃园馆外的椅子上，酒店的两女一男三位经理立即上前询问照顾，并进餐厅告知我们！经理们一边照料病人一边安慰我们，还协助我们叫来120，并迅速协助病人登车，实在是太贴心了！无比无比感动感激??????????
到中山医1??院做了必要检查，幸好儿子是急性肠胃炎，打了止痛针后症状明显缓解，我们下午就回深圳了。
晚上10点，我先生接到了花园酒店经理的电话，详细询问病人的身体状况，真是始料未及！这么贴心的服务只能是花园酒店！感激之情再次涌起??????
以后到广州入住酒店，首选花园??????', '["https://dimg04.c-ctrip.com/images/0231b12000i6b7uhy9E98_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234512000i6b8tdiE1DF_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230k12000i6b7zboD1B1_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232z12000i6b8ykv55F8_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234d12000i6b7uon6536_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0237412000i6b7z5052B6_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234p12000i6b8gphFF51_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 341, 1, 9, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('680278e3e3c98b0941765755', '过年连续入住几天。来之前看评论说入住前台排队等候时间很长。但是我入住当天觉得前台接柜工作人员速度很快。而且大堂礼仪小姐也会帮忙协助之前办好入住手续的客人领取房卡分流的很好而且主动帮助客人打开拍照大堂的春节装饰。地理位置优越出行门口就是地铁站。早餐一般。酒店中遇到的每位工作人员还是热情大方礼貌的。', '["https://dimg04.c-ctrip.com/images/0234512000i88k4w5D9A1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000i88tmtl9F13_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232512000i88wjuj71A0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2025-02-01', '花园大床房', '大床房', '家庭亲子', 148, 1, 11, 8, '["前台服务","交通便利性","餐饮设施"]'::jsonb, '前台服务', '交通便利性', '餐饮设施'),
('680278efe3c98b0941765756', '超级棒的酒店，超完美的服务。
之前看到有些差评，内心还很忐忑。
可宾馆所处的区位真是无可替代，还是犹豫中选择了这家，结果成为了这次广州行中最佳的选择。
宾馆装修后非常洁净、现代；前台小姐姐贴心地升级了房间；客房服务细心周到，主动提供咖啡和茶(小小举措，特别温馨)；宾馆所有服务人员都很主动热情……', '["https://dimg04.c-ctrip.com/images/0233l12000iicgrf18DF6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-13', '花园双床房', '双床房', '家庭亲子', 148, 0, 4, 9, '["整体满意度","前台服务","客房服务"]'::jsonb, '整体满意度', '前台服务', '客房服务'),
('680278efe3c98b0941765757', '老牌代表性酒店，各个岗位服务人员态度都很训练有素?? 春节氛围很浓，鲜花摆设处处都有。入住期间生日还有布置了房间并准备了蛋糕；房间整理清洁James观察细致，还手写留条祝新年快乐；酒店内餐点选择很多元，酒廊的茶点水果每日都有不同，Carrie热情聊天很温暖。周边出行、美食也都特别多选择。酒店博物馆很有特色，也是酒店行业发展难得的记录。唯一美中不足的部分康体设施在维修。', '["https://dimg04.c-ctrip.com/images/0234a12000i9wqn6m2639_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233c12000i9wspla4324_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j12000i9w9tdv523E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000i9wvg9q9211_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000i9wx5mp4A17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000i9vurhm0CB6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000i9w0sv942C4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.8, 4, '2025-02-03', '花园大床房', '大床房', '家庭亲子', 185, 0, 9, 9, '["前台服务","客房服务","餐饮设施"]'::jsonb, '前台服务', '客房服务', '餐饮设施'),
('680278efe3c98b0941765758', '对广州老牌子酒店有很多期待，住完广州迎宾馆来到花园酒店，大堂金碧辉煌的绘画很是震撼，春节氛围感很好，装饰热闹，还有专门给人拍摄的服务，很赞。大堂春节还有欢乐表演。房间给了升级套房，让我们体验了两种不同的房型很赞。酒店有个小博物馆让我们了解了广州酒店的发展史。花园瀑布很漂亮，喂鱼是一道风景线，孩子很欢乐。每个酒店打卡点都看了一下还是不错的，房间有不同国家的服务生，尽显花园酒店的国际化，房间服务也非常好。水、咖啡、茶都补足。不足之处：房间比较老化，没有足够的USB插口，也没有像莲花山酒店专门放一个多用途转接头。床太软太软，对我要不好的人来说睡眠是灾难，这点建议参考迎宾馆的床简直太舒服了。旋转餐厅服务体验不好，明档下面的地方没有规则，孩子大人要了两次面都被别人拿走，要么有个叫号牌，要么放在旁边等我们来拿。虽然我们现场投诉了，但来道歉的主厨看上去趾高气扬熬的傲气，可能老牌子酒店的服务就是有点高高在上的。咖啡间台拥挤，我被人踩到几次。服务生像是临时招聘，我和他说桌上餐盘收掉，他叫了别人，说他自己有点忙。瀑布餐厅玻璃不干净不能看到美景，明档的面没有楼上好吃。说实在对拥有米其林餐厅的花园酒店自助早餐实在没什么好吃的，我问了连虾饺都没有。口味不如亚朵一碗面和华夫饼。有时候老牌子也要向新品牌学习。花园酒店是广州的一个招牌，还是希望下次来入住有更好的体验。', '["https://dimg04.c-ctrip.com/images/0232k12000i6zcdi4A415_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231412000i6xpbdo14B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000i6yf89y516D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000i6y7whn3A46_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000i6z9wvv0241_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000i6y4bh99FA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233y12000i6xd57t710B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236912000i6xz2co8C2D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k12000i6yezoo7F92_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.8, 3, '2025-01-31', '花园双床房', '双床房', '家庭亲子', 577, 1, 7, 9, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('680278efe3c98b0941765759', '在广州住的四个酒店中最满意的。服务人员多，态度好，临近过年酒店大堂布置的也很喜庆。还有个酒店博物馆，可以看挺久，看得出很用心普及酒店知识，很有趣。后院小而精致，瀑布池塘里的锦鲤超级肥大，见人就过来张嘴，哈哈。酒店位置也很不错，出门就是地铁站，对面是白云宾馆和友谊商店。房间设计还不错，基本可以做到关灯全黑。唯一一点就是我的房间在布草间旁边，早上会有点吵。但服务人员的态度抵消了这点，都非常友好，超赞！', '["https://dimg04.c-ctrip.com/images/0232r12000i99blopC1C5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000i98fyd48FCC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000i981jnxB850_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230312000i99gu6n6D62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000i98u9ybCF70_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000i986tt52950_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000i984ub948EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232h12000i985axy3FCD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-02', '花园大床房', '大床房', '家庭亲子', 200, 0, 16, 9, '["前台服务","交通便利性","安静程度"]'::jsonb, '前台服务', '交通便利性', '安静程度'),
('680278efe3c98b094176575a', '设施：设施齐全，看着都挺新的
卫生：干净卫生
环境：附近就是北京路吃吃喝喝挺多的
服务：挺好的
定的套房客厅好大，房间稍微感觉小了一些些
早餐没去吃，下次去尝尝', '["https://dimg04.c-ctrip.com/images/0236112000ivlepohBFB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-04', '红棉大床套房', '套房', '其他', 80, 0, 70, 5, '["周边配套","房间设施","卫生状况"]'::jsonb, '周边配套', '房间设施', '卫生状况'),
('680278efe3c98b094176575b', '作为国内白金五星酒店，广州花园酒店也是中国酒店发展历史的重要见证者和参与者。
总体体验是不错的，房间住宿也很舒适，酒店内有多家各具特色的餐厅。
酒店四楼的博物馆，和酒店后的花园，都是值得一去的景点', '["https://dimg04.c-ctrip.com/images/0235s12000idc98yrC18C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233u12000idbkoqn00BA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2025-02-07', '红棉大床套房', '套房', '家庭亲子', 98, 0, 4, 7, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('680278efe3c98b094176575c', '带着两个娃住了两晚，体验非常棒！位置特别便利，淘金地铁a口。去逛了西湖花街，看了越秀灯会，小蛮腰，退房那天去了动物园，避开人流高峰期。可惜是少了一个浴缸玩水。其他都满分。30楼的凌璇阁旋转餐厅好棒，就是有点晒，各种品类丰富又好吃。行政礼遇的欢乐时光也非常棒！闹事里面有这么一个后花园，还藏着大瀑布。真是不住不知道。非常推荐', '["https://dimg04.c-ctrip.com/images/0234f12000i4l6imo35AF_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235912000i4l5s2iC248_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0231d12000i4l6bs603BB_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235s12000i4l6zfn7CBD_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-28', '花园双床房', '双床房', '家庭亲子', 161, 1, 1, 9, '["交通便利性","餐饮设施","整体满意度"]'::jsonb, '交通便利性', '餐饮设施', '整体满意度'),
('680278efe3c98b094176575d', '前年广交会期间住过一次花园酒店，一直念念不忘，这次全家出游果断定了，还是一样感觉很好，酒店虽然有年份了但是房间维护的很好，大厅的春节气氛也很浓厚，让人宾至如归，唯一的缺点就是房间的马桶感觉可以升级一下，还有就是中央空调必须集中供暖或者供冷，不能自己设置。', '["https://dimg04.c-ctrip.com/images/0235g12000i7zaep336CB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235i12000i808h33B88D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000i7z9fy35F60_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-02-01', '花园大床房', '大床房', '家庭亲子', 127, 0, 12, 8, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('680278efe3c98b094176575e', '过年去广州玩，带了小孩和老人，选择了广州花园酒店，酒店建设很大气，地理位置优越，出门没多远就有地铁站，5号线淘金站，我们出行都是地铁到哪里都很方便，旁边都是各种吃的，还有商场，超市。进入酒店，年味的气氛很浓，金碧辉煌，还有专人给拍照，大堂还有各种表演，挺热闹的。订的大床房，房间有点小，设施有点老旧，应该订红棉房的，但整体服务还是不错的。酒店里还有个博物馆，记录了花园酒店发展的历史，很大，后面还有个瀑布花园，带小朋友挺好逛的。', '["https://dimg04.c-ctrip.com/images/0230y12000ibpz3qo0AB1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000ibpstse9C97_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232e12000ibpwyd2074C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000ibpck393030_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000ibp6fbwC9FB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.6, 4, '2025-02-05', '花园大床房', '大床房', '家庭亲子', 214, 0, 17, 8, '["交通便利性","周边配套","整体满意度"]'::jsonb, '交通便利性', '周边配套', '整体满意度'),
('680278efe3c98b094176575f', '房间还不错，挺大的，还有咖啡机。窗户可以看到外面的景色??Tina的服务很不错，飞快帮我完成退房了??', '["https://dimg04.c-ctrip.com/images/0235q12000jrmekmz78E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000jrmixom2E21_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-13', '花园大床房', '大床房', '家庭亲子', 51, 0, 1, 5, '["房间设施","退房/入住效率","景观/朝向"]'::jsonb, '房间设施', '退房/入住效率', '景观/朝向'),
('680278fee3c98b0941765760', '很有文化底蕴的酒店，工作人员服务态度特别好，出行便利，就在地铁站边上，酒店门口也一直有排队的出租车。酒店早餐很好吃，特别是在行政酒廊外吃早餐，可以看到花园的喷泉温和小瀑布，很惬意。早餐味道也不错，服务员还会帮忙冲咖啡。就是房间有点小，带两个娃有点局促，不过性价比还是很高的。', '["https://dimg04.c-ctrip.com/images/0232812000i3qj94h808D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000i3ql9wa0CA9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236a12000i3qn2n1E9E6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-27', '花园双床房', '双床房', '家庭亲子', 137, 0, 8, 9, '["交通便利性","前台服务","性价比"]'::jsonb, '交通便利性', '前台服务', '性价比'),
('680278fee3c98b0941765761', '服务： 相当值得白金五星的服务，每一位遇到的工作人员都礼貌真诚， 办理入住的时候， 主动给我们升级。主动升级房型的酒店，真的是非常大气和有人情味。 从入住到离开，从未提过要好评，但是这个服务值得超五星好评。

环境：毋庸置疑，这是个富丽堂皇的酒店， 唯一入围白金五星的民族酒店， 建立初期就采用德国技术进行污水处理， 广州运动会的官方酒店等等等等， 无论是它的历史底蕴，还是它现在审美品味，都值得二刷三刷！

卫生：很干净，也是可以娃儿穿着背心睡的酒店。

设施：电视非常高清，有多国频道。 窗帘自动，吹风机等措施很棒， 而且， 这家提供的矿泉水也是高品质的， 还有胶囊咖啡机！唯一不足的是酒店的化妆镜，太矮了，要弯着腰化妆。真的太喜欢这家酒店的贵妃榻和迎宾馆的中式沙发了，都是特别舒服！ 配上超高清电视，舒舒服服在酒店看了两部电影，下雨天最快乐的事！

总结： 酒店很赞， 他的花园瀑布餐厅，荔枝湾餐食，还有自身的博物馆，都很值得参观。 这家酒店让我们在广州降温下雨不宜外出的日子，依然室内旅游了羊城。一定会再来的！', '["https://dimg04.c-ctrip.com/images/0233912000i5wj2peE048_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000i5wl9oeC499_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000i5x1aa814D4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000i5wopl848A3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000i5x7s2gB7B4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000i5x9cye81E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234612000i5vvsb170FD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000i5xcc8hA228_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232212000i5w6qsw768D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-30', '花园大床房', '大床房', '家庭亲子', 459, 0, 7, 9, '["前台服务","整体满意度","房间设施"]'::jsonb, '前台服务', '整体满意度', '房间设施'),
('680278fee3c98b0941765762', '不愧是老牌五星，久仰大名，第一次入住，酒店主动升级了套房，特别惊喜，好感度倍增。酒店大堂恢宏气派，设计古色古香，相比珠江新城的现代化，更喜欢花园酒店的中式设计。后花园一步一景，晒着太阳在里面散步特别舒服。4楼的博物馆值得一去。会回住的！', '["https://dimg04.c-ctrip.com/images/0233z12000i26kt8bE21C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234912000i26mr17B99A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231w12000i26jx22AB3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p12000i26mmc8DC0F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000i26b052D39B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000i262o8iA9B2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231v12000i26dgpl4916_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234212000i26zoyk7074_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-25', '花园大床房', '大床房', '商务出差', 118, 0, 4, 9, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('680278fee3c98b0941765763', '30多年前，父亲经常在花园酒店对面广州友谊商店出差，本次跟父母一同到广州怀旧之旅，首选花园酒店，满满的童年回忆！感谢入住时Kasas给我们升级了房间，房间装修温馨典雅，极具老钱风，床品舒适，瀑布餐厅就餐也很惬意！退房时，大堂金色衣服LiVen、Rain给我们服务很好，退房效率高。', '["https://dimg04.c-ctrip.com/images/0232012000jgssu8j05EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000jgsr8f1AE15_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-04-01', '花园大床房', '大床房', '家庭亲子', 140, 0, 6, 8, '["前台服务","退房/入住效率","房间设施"]'::jsonb, '前台服务', '退房/入住效率', '房间设施'),
('680278fee3c98b0941765764', '广州来过很多次，终于亲自体验了一次评价不一的花园，个人觉得值得好评，环境 布置 房间 餐饮各方面都非常大气 华贵而且价格值得，最重要的是这里的服务人员人情味很足 会主动服务并态度耐心真诚 必须给大堂的ANNA和WAYNE两位帅哥靓女五星好评！', '["https://dimg04.c-ctrip.com/images/0231812000i5gd4q301F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000i5gw9z1CA86_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237312000i5eptmz4FFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233r12000i5g0o0iD202_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232y12000i5fkdroCFF8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-30', '红棉大床套房', '套房', '家庭亲子', 121, 0, 8, 8, '["整体满意度","前台服务","性价比"]'::jsonb, '整体满意度', '前台服务', '性价比'),
('680278fee3c98b0941765765', '老店的服务一如既往的的好，来广州就夜泊花园酒店，早饮在白天鹅酒店，也许就是对老广的那种情怀。时隔七年，是我第四次来羊城，第一次带娃来住，感谢前台接待员帮我升级套房和主动提供儿童洗漱备品。闺女很喜欢瀑布餐厅，餐厅服务员给了小饼干??给小朋友喂鱼，闺女在鱼池玩得很开心，不愿离开.......期待下次还来这家酒店。', '["https://dimg04.c-ctrip.com/images/0230g12000i1qb36l50C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000i1ps97m699B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000i1pp6rn55BB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000i1q92beE383_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000i1pqul7C3E9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235612000i1punnw5DCF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-01-25', '花园大床房', '大床房', '家庭亲子', 155, 0, 23, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('680278fee3c98b0941765766', '老牌五星酒店，环境优美，位置优越，大厅富丽堂皇，布置的非常有岭南过春节的气氛。酒店里的几家馆子也非常好吃。1.3米的双床房非常适合亲子游的一家三口。房间有点小，设施旧。淋浴设计的非常不喜欢。', '["https://dimg04.c-ctrip.com/images/0233412000ia0rysc0736_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.3, 4, '2025-02-03', '城央绿意双床房', '双床房', '家庭亲子', 95, 0, 23, 8, '["房间设施","周边配套","整体满意度"]'::jsonb, '房间设施', '周边配套', '整体满意度'),
('680278fee3c98b0941765767', '低楼层客房整体装修不算过时，不过细节欠佳，房门有起皮现象，沙发也显得很旧，坐感不太舒适。

桃园餐厅菜品味道不错，食材新鲜，但服务质量参差不齐，部分服务人员缺乏专业性，遇到问题不是积极解决，而是试图把责任推给顾客。并且，住房顾客专享的用餐折扣也未主动告知，还是后来友人告知，回餐厅询问，工作人员却表示要顾客主动提才给优惠，一概不承认自己有问题。

入住期间，还因押金不足碰上服务被婉拒的状况。好在客服许经理处理问题及时又专业，让原本不太愉快的经历有所改观。客服打扫的工作人员都很细心。', '["https://dimg04.c-ctrip.com/images/0236512000jqsu2gq532F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233q12000jqu7oue0C02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234r12000jqss66hA170_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2025-04-12', '花园大床房', '大床房', '其他', 242, 0, 23, 9, '["房间设施","前台服务","餐饮设施"]'::jsonb, '房间设施', '前台服务', '餐饮设施'),
('680278fee3c98b0941765768', '1991年去过这个酒店??、一晃三十多年了、服务一流、各个方面都很棒、非常满意、这次买了套餐、性价比挺高、酒店博物馆和瀑布都很赞??特别感谢一下一个迎宾的美女、因我的手提袋子太重、她非常热心帮我找了一个酒店的袋子给我、谢谢！', '["https://dimg04.c-ctrip.com/images/0232e12000i0d9gnl9FF5_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0234312000i0dle9uD870_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235612000i0dg5vw156F_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230112000i0dl50qE977_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0236312000i0dj4s00152_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0230k12000i0dkoniF95D_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2025-01-23', '花园大床房', '大床房', '独自旅行', 112, 0, 102, 7, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('680278fee3c98b0941765769', '非常满意的入住体验，酒店的地理位置非常好，交通也很便利，出门就是地铁站，酒店的大堂非常气派，环境很好，见我带着老人和孩子，还升级了房间，房间干净舒适，服务贴心细致，设施一应俱全。非常推荐！', '["https://dimg04.c-ctrip.com/images/0235612000iuj8z1v9B04_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000iuj2vb835A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235o12000iuj5u111A3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m12000iuip8h048FF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237012000iujophp7AC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-03', '花园双床房', '双床房', '家庭亲子', 94, 0, 16, 8, '["整体满意度","交通便利性","卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况')
